const orders = items.map(i => i.json);
const totalRevenue = orders.reduce((sum, o) => sum + parseFloat(o.total || 0), 0);
const orderCount = orders.length;
const avgOrder = orderCount > 0 ? (totalRevenue / orderCount).toFixed(2) : 0;
const acimaOrders = orders.filter(o => o.payment_method === 'acima').length;
const stripeOrders = orders.filter(o => o.payment_method === 'stripe').length;

return [{
  json: {
    date: new Date().toLocaleDateString('en-US', {weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'}),
    orderCount,
    totalRevenue: totalRevenue.toFixed(2),
    avgOrder,
    acimaOrders,
    stripeOrders
  }
}];

